from difflib import SequenceMatcher
def seq_ratio(a,b):
    return SequenceMatcher(None,a,b).ratio()

def token_f1(a,b):
    ta = a.split()
    tb = b.split()
    common = sum(min(ta.count(t), tb.count(t)) for t in set(ta))
    if common==0:
        return 0.0
    precision = common / len(ta)
    recall = common / len(tb)
    if precision+recall==0:
        return 0.0
    return 2*precision*recall / (precision+recall)

def lcs_len(a,b):
    # longest common substring? implement simple DP for LCS (not substring)
    # But we'll compute longest common subsequence (LCS) length on characters
    A = a
    B = b
    m = len(A); n = len(B)
    dp = [[0]*(n+1) for _ in range(m+1)]
    for i in range(m-1,-1,-1):
        for j in range(n-1,-1,-1):
            if A[i]==B[j]:
                dp[i][j]=1+dp[i+1][j+1]
            else:
                dp[i][j]=max(dp[i+1][j], dp[i][j+1])
    lcs = dp[0][0]
    # return ratio relative to average length
    avg_len = (m+n)/2 if (m+n)>0 else 1
    return lcs/avg_len, lcs, m, n

